#!/bin/bash

# Test script for validation service endpoints
# Run this after starting the web application

BASE_URL="http://localhost:8080"

# Sample QR codes for testing
HCERT_QR='HC1:6BF+70790T9WJWG.FKY*4GO0RKPNHILCJ$VBFBBRW1*70HS8FN0WLCD/OWY01BCEKID97TK0F90KECTHGWJC0FDC:5AIA%G7X+AQB9746HS80:5AIBZ47VF6$A8VL6+0AP7BN46/46R46 463ZACN9+Y9 +AVK4WJCT3EHS8XJC$+DXJCCWENF6OF63W5NW6UF6%JC QE/IAYJC5LEW34U3ET7DXC9 QE-ED8%E.JCBECB1A-:8$966469L6OF6VX6Q$D.UDRYA 96NF6L/5SW6Y57KQEPD09WEQDD+Q6TW6FA7C466KCN9E%961A6DL6FA7D46JPCT3E5JDNA7$Q68465W51S6..DX%DZJC5/DL+8 VD 8D%$EWKEI3D:-C-3EWED1ECW.CBWEY*82T92694ZAVIAI3D8WE Y9G+95N9$PC5$CUZCY$5Y$527B789C%HQWK8E5%H4ZL2S/RS*UX51KUV:Q07WOK1DHBQZVQLTR4:1LPUR%CT M$MAW.85BNXQNF:JN408DJRP0HX48878CJD9K8BD4:F'

SHC_QR='shc:'

DIVOC_QR='B64:'

UNKNOWN_QR='UNKNOWN:12345'

echo "Testing Validation Service Endpoints"
echo "===================================="

# Test 1: Format Recognition - Any Format
echo -e "\n1. Testing format recognition for HCERT..."
curl -X POST "$BASE_URL/validation/format-recognition" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$HCERT_QR\"}" \
  | jq '.'

# Test 2: Specific Format Recognition - HCERT
echo -e "\n2. Testing specific format recognition for HCERT..."
curl -X POST "$BASE_URL/validation/format-recognition/hcert" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$HCERT_QR\"}" \
  | jq '.'

# Test 3: Specific Format Recognition - Wrong Format
echo -e "\n3. Testing specific format recognition for wrong format..."
curl -X POST "$BASE_URL/validation/format-recognition/shc" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$HCERT_QR\"}" \
  | jq '.'

# Test 4: KID Extraction
echo -e "\n4. Testing KID extraction for HCERT..."
curl -X POST "$BASE_URL/validation/kid-extraction" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$HCERT_QR\"}" \
  | jq '.'

# Test 5: Content Extraction
echo -e "\n5. Testing content extraction for HCERT..."
curl -X POST "$BASE_URL/validation/content-extraction" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$HCERT_QR\"}" \
  | jq '.'

# Test 6: Signature Validation
echo -e "\n6. Testing signature validation for HCERT..."
curl -X POST "$BASE_URL/validation/signature-validation" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$HCERT_QR\"}" \
  | jq '.'

# Test 7: KID Environment Check
echo -e "\n7. Testing KID environment check..."
curl -X POST "$BASE_URL/validation/kid-environment" \
  -H "Content-Type: application/json" \
  -d "{\"kid\": \"test_kid_123\"}" \
  | jq '.'

# Test 8: Unknown Format
echo -e "\n8. Testing unknown format..."
curl -X POST "$BASE_URL/validation/format-recognition" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$UNKNOWN_QR\"}" \
  | jq '.'

# Test 9: SHC Format
echo -e "\n9. Testing SHC format recognition..."
curl -X POST "$BASE_URL/validation/format-recognition" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$SHC_QR\"}" \
  | jq '.'

# Test 10: DIVOC Format
echo -e "\n10. Testing DIVOC format recognition..."
curl -X POST "$BASE_URL/validation/format-recognition" \
  -H "Content-Type: application/json" \
  -d "{\"uri\": \"$DIVOC_QR\"}" \
  | jq '.'

echo -e "\n===================================="
echo "Testing completed!"